3573       all_of(GEP.indices(), [&](Value *Idx) {
3574         return isKnownNonNegative(Idx, SQ.getWithInstruction(&GEP));
3575       })) {
3576     GEP.setNoWrapFlags(GEP.getNoWrapFlags() | GEPNoWrapFlags::noUnsignedWrap());
3577     return &GEP;
3578   }
3579 
3580   // These rewrites are trying to preserve inbounds/nuw attributes. So we want
3581   // to do this after having tried to derive "nuw" above.
3582   if (GEP.getNumIndices() == 1) {
3583     // Given (gep p, x+y) we want to determine the common nowrap flags for both
3584     // geps if transforming into (gep (gep p, x), y).
3585     auto GetPreservedNoWrapFlags = [&](bool AddIsNUW) {
3586       // We can preserve both "inbounds nuw", "nusw nuw" and "nuw" if we know
3587       // that x + y does not have unsigned wrap.
3588       if (GEP.hasNoUnsignedWrap() && AddIsNUW)
3589         return GEP.getNoWrapFlags();
3590       return GEPNoWrapFlags::none();
3591     };
