3594     Value *Idx1, *Idx2;
3595     if (match(GEP.getOperand(1),
3596               m_OneUse(m_AddLike(m_Value(Idx1), m_Value(Idx2))))) {
3597       //   %idx = add i64 %idx1, %idx2
3598       //   %gep = getelementptr i32, ptr %ptr, i64 %idx
3599       // as:
3600       //   %newptr = getelementptr i32, ptr %ptr, i64 %idx1
3601       //   %newgep = getelementptr i32, ptr %newptr, i64 %idx2
3602       bool NUW = match(GEP.getOperand(1), m_NUWAddLike(m_Value(), m_Value()));
3603       GEPNoWrapFlags NWFlags = GetPreservedNoWrapFlags(NUW);
3604       auto *NewPtr =
3605           Builder.CreateGEP(GEP.getSourceElementType(), GEP.getPointerOperand(),
3606                             Idx1, "", NWFlags);
3607       return replaceInstUsesWith(GEP,
3608                                  Builder.CreateGEP(GEP.getSourceElementType(),
3609                                                    NewPtr, Idx2, "", NWFlags));
3610     }
3611     ConstantInt *C;
3612     if (match(GEP.getOperand(1), m_OneUse(m_SExtLike(m_OneUse(m_NSWAddLike(
3613                                      m_Value(Idx1), m_ConstantInt(C))))))) {
3614       // %add = add nsw i32 %idx1, idx2
3615       // %sidx = sext i32 %add to i64
3616       // %gep = getelementptr i32, ptr %ptr, i64 %sidx
3617       // as:
3618       // %newptr = getelementptr i32, ptr %ptr, i32 %idx1
3619       // %newgep = getelementptr i32, ptr %newptr, i32 idx2
3620       bool NUW = match(GEP.getOperand(1),
3621                        m_NNegZExt(m_NUWAddLike(m_Value(), m_Value())));
3622       GEPNoWrapFlags NWFlags = GetPreservedNoWrapFlags(NUW);
3623       auto *NewPtr = Builder.CreateGEP(
3624           GEP.getSourceElementType(), GEP.getPointerOperand(),
3625           Builder.CreateSExt(Idx1, GEP.getOperand(1)->getType()), "", NWFlags);
3626       return replaceInstUsesWith(
3627           GEP,
3628           Builder.CreateGEP(GEP.getSourceElementType(), NewPtr,
3629                             Builder.CreateSExt(C, GEP.getOperand(1)->getType()),
3630                             "", NWFlags));
3631     }
3632   }
3633 
3634   if (Instruction *R = foldSelectGEP(GEP, Builder))
3635     return R;
3636 
3637   return nullptr;
3638 }
