3640 static bool isNeverEqualToUnescapedAlloc(Value *V, const TargetLibraryInfo &TLI,
3641                                          Instruction *AI) {
3642   if (isa<ConstantPointerNull>(V))
3643     return true;
3644   if (auto *LI = dyn_cast<LoadInst>(V))
3645     return isa<GlobalVariable>(LI->getPointerOperand());
3646   // Two distinct allocations will never be equal.
3647   return isAllocLikeFn(V, &TLI) && V != AI;
