3650 /// Given a call CB which uses an address UsedV, return true if we can prove the
3651 /// call's only possible effect is storing to V.
3652 static bool isRemovableWrite(CallBase &CB, Value *UsedV,
3653                              const TargetLibraryInfo &TLI) {
3654   if (!CB.use_empty())
3655     // TODO: add recursion if returned attribute is present
3656     return false;
3657 
3658   if (CB.isTerminator())
3659     // TODO: remove implementation restriction
3660     return false;
3661 
3662   if (!CB.willReturn() || !CB.doesNotThrow())
3663     return false;
3664 
3665   // If the only possible side effect of the call is writing to the alloca,
3666   // and the result isn't used, we can safely remove any reads implied by the
3667   // call including those which might read the alloca itself.
3668   std::optional<MemoryLocation> Dest = MemoryLocation::getForDest(&CB, TLI);
3669   return Dest && Dest->Ptr == UsedV;
3670 }
