3672 static std::optional<ModRefInfo>
3673 isAllocSiteRemovable(Instruction *AI, SmallVectorImpl<WeakTrackingVH> &Users,
3674                      const TargetLibraryInfo &TLI, bool KnowInit) {
3675   SmallVector<Instruction*, 4> Worklist;
3676   const std::optional<StringRef> Family = getAllocationFamily(AI, &TLI);
3677   Worklist.push_back(AI);
3678   ModRefInfo Access = KnowInit ? ModRefInfo::NoModRef : ModRefInfo::Mod;
3679 
3680   do {
3681     Instruction *PI = Worklist.pop_back_val();
3682     for (User *U : PI->users()) {
3683       Instruction *I = cast<Instruction>(U);
3684       switch (I->getOpcode()) {
3685       default:
3686         // Give up the moment we see something we can't handle.
3687         return std::nullopt;
3688 
3689       case Instruction::AddrSpaceCast:
3690       case Instruction::BitCast:
3691       case Instruction::GetElementPtr:
3692         Users.emplace_back(I);
3693         Worklist.push_back(I);
3694         continue;
3695 
3696       case Instruction::ICmp: {
3697         ICmpInst *ICI = cast<ICmpInst>(I);
3698         // We can fold eq/ne comparisons with null to false/true, respectively.
3699         // We also fold comparisons in some conditions provided the alloc has
3700         // not escaped (see isNeverEqualToUnescapedAlloc).
3701         if (!ICI->isEquality())
3702           return std::nullopt;
3703         unsigned OtherIndex = (ICI->getOperand(0) == PI) ? 1 : 0;
3704         if (!isNeverEqualToUnescapedAlloc(ICI->getOperand(OtherIndex), TLI, AI))
3705           return std::nullopt;
3706 
3707         // Do not fold compares to aligned_alloc calls, as they may have to
3708         // return null in case the required alignment cannot be satisfied,
3709         // unless we can prove that both alignment and size are valid.
3710         auto AlignmentAndSizeKnownValid = [](CallBase *CB) {
3711           // Check if alignment and size of a call to aligned_alloc is valid,
3712           // that is alignment is a power-of-2 and the size is a multiple of the
3713           // alignment.
3714           const APInt *Alignment;
3715           const APInt *Size;
3716           return match(CB->getArgOperand(0), m_APInt(Alignment)) &&
3717                  match(CB->getArgOperand(1), m_APInt(Size)) &&
3718                  Alignment->isPowerOf2() && Size->urem(*Alignment).isZero();
3719         };
3720         auto *CB = dyn_cast<CallBase>(AI);
3721         LibFunc TheLibFunc;
3722         if (CB && TLI.getLibFunc(*CB->getCalledFunction(), TheLibFunc) &&
3723             TLI.has(TheLibFunc) && TheLibFunc == LibFunc_aligned_alloc &&
3724             !AlignmentAndSizeKnownValid(CB))
3725           return std::nullopt;
3726         Users.emplace_back(I);
3727         continue;
3728       }
3729 
3730       case Instruction::Call:
3731         // Ignore no-op and store intrinsics.
3732         if (IntrinsicInst *II = dyn_cast<IntrinsicInst>(I)) {
3733           switch (II->getIntrinsicID()) {
3734           default:
3735             return std::nullopt;
3736 
3737           case Intrinsic::memmove:
3738           case Intrinsic::memcpy:
3739           case Intrinsic::memset: {
3740             MemIntrinsic *MI = cast<MemIntrinsic>(II);
3741             if (MI->isVolatile())
3742               return std::nullopt;
3743             // Note: this could also be ModRef, but we can still interpret that
3744             // as just Mod in that case.
3745             ModRefInfo NewAccess =
3746                 MI->getRawDest() == PI ? ModRefInfo::Mod : ModRefInfo::Ref;
3747             if ((Access & ~NewAccess) != ModRefInfo::NoModRef)
3748               return std::nullopt;
3749             Access |= NewAccess;
3750             [[fallthrough]];
3751           }
3752           case Intrinsic::assume:
3753           case Intrinsic::invariant_start:
3754           case Intrinsic::invariant_end:
3755           case Intrinsic::lifetime_start:
3756           case Intrinsic::lifetime_end:
3757           case Intrinsic::objectsize:
3758             Users.emplace_back(I);
3759             continue;
3760           case Intrinsic::launder_invariant_group:
3761           case Intrinsic::strip_invariant_group:
3762             Users.emplace_back(I);
3763             Worklist.push_back(I);
3764             continue;
3765           }
3766         }
3767 
3768         if (Family && getFreedOperand(cast<CallBase>(I), &TLI) == PI &&
3769             getAllocationFamily(I, &TLI) == Family) {
3770           Users.emplace_back(I);
3771           continue;
3772         }
3773 
3774         if (Family && getReallocatedOperand(cast<CallBase>(I)) == PI &&
3775             getAllocationFamily(I, &TLI) == Family) {
3776           Users.emplace_back(I);
3777           Worklist.push_back(I);
3778           continue;
3779         }
3780 
3781         if (!isRefSet(Access) &&
3782             isRemovableWrite(*cast<CallBase>(I), PI, TLI)) {
3783           Access |= ModRefInfo::Mod;
3784           Users.emplace_back(I);
3785           continue;
3786         }
3787 
3788         return std::nullopt;
3789 
3790       case Instruction::Store: {
3791         StoreInst *SI = cast<StoreInst>(I);
3792         if (SI->isVolatile() || SI->getPointerOperand() != PI)
3793           return std::nullopt;
3794         if (isRefSet(Access))
3795           return std::nullopt;
3796         Access |= ModRefInfo::Mod;
3797         Users.emplace_back(I);
3798         continue;
3799       }
3800 
3801       case Instruction::Load: {
3802         LoadInst *LI = cast<LoadInst>(I);
3803         if (LI->isVolatile() || LI->getPointerOperand() != PI)
3804           return std::nullopt;
3805         if (isModSet(Access))
3806           return std::nullopt;
3807         Access |= ModRefInfo::Ref;
3808         Users.emplace_back(I);
3809         continue;
3810       }
3811       }
3812       llvm_unreachable("missing a return?");
3813     }
3814   } while (!Worklist.empty());
3815 
3816   assert(Access != ModRefInfo::ModRef);
3817   return Access;
