3823   // If we have a malloc call which is only used in any amount of comparisons to
3824   // null and free calls, delete the calls and replace the comparisons with true
3825   // or false as appropriate.
3826 
3827   // This is based on the principle that we can substitute our own allocation
3828   // function (which will never return null) rather than knowledge of the
3829   // specific function being called. In some sense this can change the permitted
3830   // outputs of a program (when we convert a malloc to an alloca, the fact that
3831   // the allocation is now on the stack is potentially visible, for example),
3832   // but we believe in a permissible manner.
3833   SmallVector<WeakTrackingVH, 64> Users;
3834 
3835   // If we are removing an alloca with a dbg.declare, insert dbg.value calls
3836   // before each store.
3837   SmallVector<DbgVariableRecord *, 8> DVRs;
3838   std::unique_ptr<DIBuilder> DIB;
3839   if (isa<AllocaInst>(MI)) {
3840     findDbgUsers(&MI, DVRs);
3841     DIB.reset(new DIBuilder(*MI.getModule(), /*AllowUnresolved=*/false));
3842   }
3843 
3844   // Determine what getInitialValueOfAllocation would return without actually
3845   // allocating the result.
3846   bool KnowInitUndef = false;
3847   bool KnowInitZero = false;
