3851     if (isa<UndefValue>(Init))
3852       KnowInitUndef = true;
3853     else if (Init->isNullValue())
3854       KnowInitZero = true;
3855   }
3856   // The various sanitizers don't actually return undef memory, but rather
3857   // memory initialized with special forms of runtime poison
3858   auto &F = *MI.getFunction();
3859   if (F.hasFnAttribute(Attribute::SanitizeMemory) ||
3860       F.hasFnAttribute(Attribute::SanitizeAddress))
3861     KnowInitUndef = false;
