2784   GEPNoWrapFlags NW = GEPNoWrapFlags::all();
2785   SmallVector<GetElementPtrInst *> Skipped;
2786   auto *InnerGEP = dyn_cast<GetElementPtrInst>(GEP.getPointerOperand());
2787   while (true) {
2788     if (!InnerGEP)
